          "assignee": "string",
          "createdAt": "number (epoch ms)",
          "closedAt": "number (epoch ms, 0 = open)",
          "syncStatus": "SyncStatus"
        }
      }
    },
    "enums": {
      "RecordCategory": "fire | electrical | mechanical | environment | personnel | other",
      "RecordStatus": "open | closed",
      "RiskSeverity": "high | medium | low",
      "RiskStatus": "open | in-progress | closed",
      "InspectionStatus": "in-progress | completed",
      "RectificationStatus": "pending | in-progress | closed | verified",
      "SyncStatus": "local | synced"
    },
    "formState": {
      "recordDraft": "editable SafetyRecord fields before save-record",
      "riskDraft": "editable RiskReport fields before submit-risk-report",
      "contactDraft": "editable Contact fields before save-contact",
      "inspectionNotesDraft": "current round notes before finish"
    },
    "computedState": {
      "summary.openRisks": "count of RiskReport where status != closed",
      "summary.pendingRectifications": "count of RectificationTask where status in (pending, in-progress)",
      "summary.todayInspections": "count of InspectionRound started today",
