      "dashboard.totalRecords": "count of SafetyRecord",
      "dashboard.openRisks": "count of RiskReport status != closed",
      "dashboard.completedInspections": "count of InspectionRound status == completed",
      "dashboard.completionRate": "same as summary.completionRate",
      "dashboard.riskTrend": "open-risk counts bucketed by recent days (array of {label,value})",
      "dashboard.categoryDistribution": "risk counts grouped by RecordCategory (array of {label,value})",
      "dashboard.topRisks": "RiskReport list sorted by severity then createdAt desc, limited",
      "records.recent": "SafetyRecord list sorted by createdAt desc, limited",
      "rectifications.urgent": "RectificationTask where overdue or status pending/in-progress, sorted by dueDate"
    },
    "persistence": {
      "strategy": "Local-first via @ohos.data.preferences. Each entity collection persisted as one JSON blob under its own preference key. In-memory repositories hydrate on init and save on mutation. syncStatus reserved for future backend; defaults to 'local'."
    }
  },
  "services": {
    "IdGenerator": "Deterministic-ish id provider (timestamp + counter) for new entities.",
    "PersistenceService": "Async wrapper over @ohos.data.preferences: loadCollection/saveCollection per entity key. Tolerates missing preferences (returns empty).",
    "RecordRepository": "CRUD + recent() + search/filter for SafetyRecord.",
    "RiskRepository": "CRUD + byStatus + counts for RiskReport.",
    "InspectionRepository": "current round get/set, history list, persist on stop changes.",
    "ContactRepository": "CRUD + search for Contact.",
    "RectificationRepository": "CRUD + byStatus + urgent() + counts + progress update.",
    "AppStore": "Central controller: owns repositories, exposes event methods + computed getters. Notifies consumers via callback registration (UI wiring done in visual phase)."
  },
  "stateMachine": {
    "InspectionRound": {
      "states": ["idle", "in-progress", "completed"],
      "transitions": [
        { "from": "idle", "event": "start-inspection-round", "to": "in-progress", "effects": ["create round", "persist"] },
        { "from": "in-progress", "event": "checkin-inspection-stop", "to": "in-progress", "effects": ["mark stop checkedInAt", "persist"] },
        { "from": "in-progress", "event": "finish-inspection-round", "to": "completed", "effects": ["set finishedAt", "persist"] }
      ]
    },
    "RiskReport": {
      "states": ["draft", "open", "in-progress", "closed"],
      "transitions": [
        { "from": "draft", "event": "submit-risk-report", "to": "open", "effects": ["validate required fields", "create linked RectificationTask (status pending)", "persist both"] },
        { "from": "draft", "event": "cancel-risk-report", "to": "draft", "effects": ["discard draft"] },
        { "from": "open|in-progress", "event": "rectification-status-changed", "to": "closed", "guard": "linked task verified/closed", "effects": ["persist"] }
      ]
    },
    "RectificationTask": {
      "states": ["pending", "in-progress", "closed", "verified"],
      "transitions": [
        { "from": "pending", "event": "update-rectification-progress (>0)", "to": "in-progress" },
        { "from": "any", "event": "save-rectification-progress", "effects": ["set progress + status per picker", "if status verified set closedAt", "persist"] }
      ]
    },
    "SafetyRecord": {
      "states": ["draft", "open", "closed"],
      "transitions": [
        { "from": "draft", "event": "save-record", "to": "open", "guard": "title non-empty", "effects": ["persist"] }
      ]
    },
    "Contact": {
      "states": ["draft", "saved"],
      "transitions": [
        { "from": "draft", "event": "save-contact", "to": "saved", "guard": "name+phone non-empty", "effects": ["persist"] }
      ]
    }
  },
  "interactionFlows": [
    {
      "id": "flow-submit-risk",
      "trigger": "home-quick-action-report / risk-submit-button",
      "inputs": ["risk-title-input", "risk-severity-picker", "risk-location-input", "risk-description-input", "risk-due-date-picker", "risk-photo-picker", "risk-assignee-input"],
      "steps": [
        "open risk-report sheet",
        "collect draft fields via update-* events",
        "on submit-risk-report: validate title + description non-empty, severity set",
        "create RiskReport(status open, createdAt now)",
        "auto-create RectificationTask(title from risk, sourceRiskId, status pending, dueDate from risk)",
        "persist both, link ids",
        "close sheet, raise success feedback"
      ],
      "errorPath": "invalid fields -> keep sheet open, surface validation message"
    },
    {
      "id": "flow-save-record",
      "trigger": "records-add-button / home-quick-action-record / record-save-button",
      "inputs": ["record-title-input", "record-category-picker", "record-description-input", "record-location-input"],
      "steps": ["open add-record sheet", "collect draft", "validate title non-empty", "create SafetyRecord(status open, createdAt now)", "persist", "close sheet"],
      "errorPath": "empty title -> block save, show validation"
    },
    {
      "id": "flow-inspection-round",
      "trigger": "inspections-start-round-button",
      "inputs": ["inspection-notes-input"],
      "steps": ["create InspectionRound(status in-progress) with default stops", "checkin-inspection-stop marks current stop", "update-inspection-notes updates round notes", "finish-inspection-round sets finishedAt + status completed", "persist each step"],
      "errorPath": "no active round -> checkin/finish disabled"
    },
    {
      "id": "flow-call-contact",
      "trigger": "contact-call-button",
      "steps": ["resolve selected contact phone", "invoke TelephonyKit call.makeCall(phone)", "surface system dialer"],
      "errorPath": "empty phone -> show feedback, do not dial"
    },
    {
      "id": "flow-update-rectification",
      "trigger": "rectification-update-progress-button / rectification-save-button",
      "inputs": ["rectification-progress-slider", "rectification-status-picker"],
      "steps": ["open update-progress sheet for task", "adjust progress + status", "save -> update task, set closedAt if verified/closed, if sourceRiskId set and verified -> close linked RiskReport", "persist", "close sheet"],
      "errorPath": "progress out of range -> clamp 0-100"
    },
    {
      "id": "flow-search-filter-records",
      "trigger": "records-search-input / records-filter-chip-*",
      "steps": ["apply query substring to title/description/location", "apply status filter (open/closed)", "re-render records-list"]
    },
    {
      "id": "flow-dashboard-period",
      "trigger": "dashboard-period-picker / change-dashboard-period",
      "steps": ["recompute riskTrend + counts for selected period"]
    }
  ],
  "testTargets": [
    "home-summary-open-risks",
    "home-summary-pending-rectifications",
    "home-summary-today-inspections",
    "home-summary-completion-rate",
    "home-quick-action-report",
    "home-recent-records-list",
    "inspections-start-round-button",
    "inspections-history-list",
    "records-search-input",
    "records-add-button",
    "records-list",
    "risk-title-input",
    "risk-severity-picker",
    "risk-submit-button",
    "contacts-list",
    "contact-call-button",
    "rectification-list",
    "rectification-segment-pending",
    "rectification-update-progress-button",
    "dashboard-stat-total-records",
    "dashboard-stat-completion-rate",
    "dashboard-risk-trend-chart"
